import React, { useEffect, useState } from 'react';
import { useParams, Link } from 'react-router-dom';
import { getAnalysisById } from '../services/resume';
import {
  ChartBarIcon,
  CheckCircleIcon,
  XCircleIcon,
  LightBulbIcon,
  ArrowPathIcon,
  ArrowLeftIcon
} from '@heroicons/react/24/outline';

const Result = () => {
  const { id } = useParams();
  const [analysis, setAnalysis] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    loadAnalysis();
  }, [id]);

  const loadAnalysis = async () => {
    try {
      const data = await getAnalysisById(id);
      setAnalysis(data);
    } catch (error) {
      console.error('Failed to load analysis:', error);
    } finally {
      setLoading(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-center">
          <ArrowPathIcon className="h-12 w-12 text-indigo-600 animate-spin mx-auto mb-4" />
          <p className="text-gray-600">Loading analysis results...</p>
        </div>
      </div>
    );
  }

  if (!analysis) {
    return (
      <div className="text-center py-12">
        <p className="text-gray-500 text-lg mb-4">Analysis not found</p>
        <Link to="/" className="btn-primary inline-flex">
          Go to Dashboard
        </Link>
      </div>
    );
  }

  const getScoreColor = (score) => {
    if (score >= 80) return 'text-green-600';
    if (score >= 60) return 'text-yellow-600';
    return 'text-red-600';
  };

  const getProgressColor = (score) => {
    if (score >= 80) return 'bg-green-600';
    if (score >= 60) return 'bg-yellow-600';
    return 'bg-red-600';
  };

  const getScoreMessage = (score) => {
    if (score >= 80) return 'Excellent! Your resume is well-optimized.';
    if (score >= 60) return 'Good, but there\'s room for improvement.';
    return 'Needs significant improvement.';
  };

  return (
    <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
      {/* Header */}
      <div className="mb-8 flex items-center justify-between">
        <div>
          <Link to="/" className="text-sm text-gray-500 hover:text-gray-700 flex items-center mb-2">
            <ArrowLeftIcon className="h-4 w-4 mr-1" />
            Back to Dashboard
          </Link>
          <h1 className="text-3xl font-bold text-gray-900">Analysis Result</h1>
          <p className="text-gray-600 mt-1">Here's how you stack up against the role.</p>
        </div>
        <div className="text-right">
          <p className="text-sm text-gray-500">Analyzed on</p>
          <p className="font-medium">
            {new Date(analysis.createdAt).toLocaleDateString('en-US', {
              month: 'long',
              day: 'numeric',
              year: 'numeric'
            })}
          </p>
        </div>
      </div>

      {/* Score Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="card">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">ATS Score</h3>
            <ChartBarIcon className="h-6 w-6 text-gray-400" />
          </div>
          <div className="relative pt-1">
            <div className="flex mb-2 items-center justify-between">
              <div>
                <span className="text-xs font-semibold inline-block py-1 px-2 uppercase rounded-full text-indigo-600 bg-indigo-200">
                  Overall Resume Optimization
                </span>
              </div>
              <div className="text-right">
                <span className={`text-3xl font-bold ${getScoreColor(analysis.atsScore)}`}>
                  {analysis.atsScore}%
                </span>
              </div>
            </div>
            <div className="overflow-hidden h-4 mb-2 text-xs flex rounded-full bg-gray-200">
              <div
                style={{ width: `${analysis.atsScore}%` }}
                className={`shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center rounded-full ${getProgressColor(analysis.atsScore)}`}
              />
            </div>
            <p className="text-sm text-gray-600">{getScoreMessage(analysis.atsScore)}</p>
          </div>
        </div>

        <div className="card">
          <div className="flex items-center justify-between mb-4">
            <h3 className="text-lg font-semibold text-gray-900">Skills Match</h3>
            <CheckCircleIcon className="h-6 w-6 text-gray-400" />
          </div>
          <div className="relative pt-1">
            <div className="flex mb-2 items-center justify-between">
              <div>
                <span className="text-xs font-semibold inline-block py-1 px-2 uppercase rounded-full text-green-600 bg-green-200">
                  Alignment with Job Requirements
                </span>
              </div>
              <div className="text-right">
                <span className={`text-3xl font-bold ${getScoreColor(analysis.matchPercentage)}`}>
                  {analysis.matchPercentage}%
                </span>
              </div>
            </div>
            <div className="overflow-hidden h-4 mb-2 text-xs flex rounded-full bg-gray-200">
              <div
                style={{ width: `${analysis.matchPercentage}%` }}
                className={`shadow-none flex flex-col text-center whitespace-nowrap text-white justify-center rounded-full ${getProgressColor(analysis.matchPercentage)}`}
              />
            </div>
            <p className="text-sm text-gray-600">
              {analysis.matchPercentage >= 70 ? 'Strong match!' : 'Consider adding more relevant skills.'}
            </p>
          </div>
        </div>
      </div>

      {/* Skills Section */}
      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="card">
          <div className="flex items-center mb-4">
            <CheckCircleIcon className="h-6 w-6 text-green-500 mr-2" />
            <h3 className="text-lg font-semibold text-gray-900">
              Skills Found ({analysis.foundSkills?.length || 0})
            </h3>
          </div>
          {analysis.foundSkills?.length > 0 ? (
            <div className="flex flex-wrap gap-2">
              {analysis.foundSkills.map((skill, index) => (
                <span
                  key={index}
                  className="px-3 py-1.5 bg-green-100 text-green-800 rounded-lg text-sm font-medium"
                >
                  {skill}
                </span>
              ))}
            </div>
          ) : (
            <p className="text-gray-500">No matching skills found</p>
          )}
        </div>

        <div className="card">
          <div className="flex items-center mb-4">
            <XCircleIcon className="h-6 w-6 text-red-500 mr-2" />
            <h3 className="text-lg font-semibold text-gray-900">
              Missing Skills ({analysis.missingSkills?.length || 0})
            </h3>
          </div>
          {analysis.missingSkills?.length > 0 ? (
            <div className="flex flex-wrap gap-2">
              {analysis.missingSkills.map((skill, index) => (
                <span
                  key={index}
                  className="px-3 py-1.5 bg-red-100 text-red-800 rounded-lg text-sm font-medium"
                >
                  {skill}
                </span>
              ))}
            </div>
          ) : (
            <p className="text-gray-500">No missing skills - Great job!</p>
          )}
        </div>
      </div>

      {/* Suggestions */}
      <div className="card mb-8">
        <div className="flex items-center mb-4">
          <LightBulbIcon className="h-6 w-6 text-yellow-500 mr-2" />
          <h3 className="text-lg font-semibold text-gray-900">
            Improvement Suggestions ({analysis.suggestions?.length || 0})
          </h3>
        </div>
        {analysis.suggestions?.length > 0 ? (
          <ul className="space-y-4">
            {analysis.suggestions.map((suggestion, index) => (
              <li key={index} className="flex items-start">
                <span className="inline-flex items-center justify-center w-6 h-6 bg-indigo-100 text-indigo-800 rounded-full text-sm font-medium mr-3 flex-shrink-0">
                  {index + 1}
                </span>
                <span className="text-gray-700">{suggestion}</span>
              </li>
            ))}
          </ul>
        ) : (
          <p className="text-gray-500">No suggestions - Your resume looks great!</p>
        )}
      </div>

      {/* Quick Stats */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4 mb-8">
        <div className="card text-center">
          <p className="text-sm text-gray-500 mb-1">Found Skills</p>
          <p className="text-4xl font-bold text-indigo-600">{analysis.foundSkills?.length || 0}</p>
        </div>
        <div className="card text-center">
          <p className="text-sm text-gray-500 mb-1">Missing Skills</p>
          <p className="text-4xl font-bold text-red-600">{analysis.missingSkills?.length || 0}</p>
        </div>
        <div className="card text-center">
          <p className="text-sm text-gray-500 mb-1">Suggestions</p>
          <p className="text-4xl font-bold text-yellow-600">{analysis.suggestions?.length || 0}</p>
        </div>
      </div>

      {/* Action Buttons */}
      <div className="flex justify-center space-x-4">
        <Link to="/analyze" className="btn-primary">
          New Analysis
        </Link>
        <button
          onClick={() => window.print()}
          className="btn-secondary"
        >
          Save Results
        </button>
      </div>
    </div>
  );
};

export default Result;
